class Solution:
    def maxSelectedElements(self, nums: List[int]) -> int:
        from collections import defaultdict

        nums.sort()
        n = len(nums)
        dp = defaultdict(int)

        for i in range(n - 1, -1, -1):
            val = nums[i]
            # Try increasing by 1
            dp[val + 1] = dp[val + 1] + 1 if dp[val + 1] < dp[val] + 1 else dp[val + 1]
            # Try not increasing
            dp[val] = dp[val] + 1 if dp[val] < dp[val] + 1 else dp[val]

        return max(dp.values())
